	// Deal RPCs (Phase 4 -- deal lifecycle)
	CreateDeal(context.Context, *CreateDealRequest) (*CreateDealResponse, error)
	// CreateExternalDeal creates a deal on behalf of a trusted external system
	// (admin panel, partner website) authenticated by the BFF's API-key
	// gateway. Skips user-level permission checks — caller is authenticated
	// at the BFF boundary, not by a cg-users JWT. Uses a dedicated request
	// message so the external path can evolve independently of the UI path
	// (lookup-or-create contact/vehicle, idempotent upsert with history,
	// merge-on-resubmit semantics for photos and other repeat-submissions).
	CreateExternalDeal(context.Context, *CreateExternalDealRequest) (*CreateExternalDealResponse, error)
	GetDeal(context.Context, *GetDealRequest) (*GetDealResponse, error)
	ListDeals(context.Context, *ListDealsRequest) (*ListDealsResponse, error)
	UpdateDeal(context.Context, *UpdateDealRequest) (*UpdateDealResponse, error)
	MoveDealStage(context.Context, *MoveDealStageRequest) (*MoveDealStageResponse, error)
	CloseDeal(context.Context, *CloseDealRequest) (*CloseDealResponse, error)
	ReOpenDeal(context.Context, *ReOpenDealRequest) (*ReOpenDealResponse, error)
	GetDealActivities(context.Context, *GetDealActivitiesRequest) (*GetDealActivitiesResponse, error)
	GetContactActivities(context.Context, *GetContactActivitiesRequest) (*GetContactActivitiesResponse, error)
	// GetPipelineAggregates returns board-wide kanban KPIs for the given
	// pipeline: tasks_today / no_task / overdue / new_today / new_yesterday /
	// forecast. Computed with a single SQL over the full pipeline so the
	// counts are consistent whether the manager has lazy-loaded every column
	// or not. Optional date_from/date_to narrow the "new deals" window and
	// the forecast set (expected_close within range) — the task-related
	// counters are absolute (today / overdue in server time), unaffected.
	GetPipelineAggregates(context.Context, *GetPipelineAggregatesRequest) (*GetPipelineAggregatesResponse, error)
	// ImportDeal upserts a deal identified by external_id stored in custom_fields.
	// Used for migrating data from external CRMs (AmoCRM, Bitrix, etc.) without
	// creating duplicates on re-imports.
	//
	// Behavior:
	//   - Searches for an existing deal where custom_fields->>'external_id' = request.external_id
	//     within (organization_id, pipeline_id).
	//   - If found: updates stage, title, amount, user_id, assigned_to, status, custom_fields.
	//   - If not found: creates a new deal with the provided created_at preserved.
	//   - Returns the deal and a `created` flag.
	//
	// Bypasses the standard CreateDeal validations that don't apply to imports
	// (e.g. allows direct creation in terminal stages with status=won|lost).
	// Authorization: requires platform admin role.
	ImportDeal(context.Context, *ImportDealRequest) (*ImportDealResponse, error)
	// PatchDealCustomFields merges (or replaces) the deal's custom_fields
	// JSONB blob. Used by external-integration backfills (hh.ru migration,
	// partner data sync) that need to enrich an existing deal without going
	// through ImportDeal's external_id dedup (useful when the old deal
	// predates the external_id scheme).
	PatchDealCustomFields(context.Context, *PatchDealCustomFieldsRequest) (*PatchDealCustomFieldsResponse, error)
