	DeleteCustomFieldDefinition(context.Context, *DeleteCustomFieldDefinitionRequest) (*DeleteCustomFieldDefinitionResponse, error)
	// Webhook Subscription RPCs (Phase 7 -- webhook delivery)
	CreateWebhookSubscription(context.Context, *CreateWebhookSubscriptionRequest) (*CreateWebhookSubscriptionResponse, error)
	ListWebhookSubscriptions(context.Context, *ListWebhookSubscriptionsRequest) (*ListWebhookSubscriptionsResponse, error)
	UpdateWebhookSubscription(context.Context, *UpdateWebhookSubscriptionRequest) (*UpdateWebhookSubscriptionResponse, error)
	DeleteWebhookSubscription(context.Context, *DeleteWebhookSubscriptionRequest) (*DeleteWebhookSubscriptionResponse, error)
	// Analytics RPCs (Phase 8)
	GetFunnelConversion(context.Context, *GetFunnelConversionRequest) (*GetFunnelConversionResponse, error)
	GetManagerStats(context.Context, *GetManagerStatsRequest) (*GetManagerStatsResponse, error)
	GetDealVolume(context.Context, *GetDealVolumeRequest) (*GetDealVolumeResponse, error)
	GetStageStats(context.Context, *GetStageStatsRequest) (*GetStageStatsResponse, error)
	// Dashboard-focused aggregates — per-user activity counts and
	// deal-source breakdown. Both support an optional user_id filter so
	// admins can request their own stats instead of org-wide totals.
	GetActivityStats(context.Context, *GetActivityStatsRequest) (*GetActivityStatsResponse, error)
	GetDealSourcesBreakdown(context.Context, *GetDealSourcesBreakdownRequest) (*GetDealSourcesBreakdownResponse, error)
	// Notes RPCs
	CreateNote(context.Context, *CreateNoteRequest) (*CreateNoteResponse, error)
	UpdateNote(context.Context, *UpdateNoteRequest) (*UpdateNoteResponse, error)
	// WhatsApp messaging RPCs
	SendWhatsAppMessage(context.Context, *SendWhatsAppMessageRequest) (*SendWhatsAppMessageResponse, error)
	SendWhatsAppTemplate(context.Context, *SendWhatsAppTemplateRequest) (*SendWhatsAppTemplateResponse, error)
	ListWhatsAppMessages(context.Context, *ListWhatsAppMessagesRequest) (*ListWhatsAppMessagesResponse, error)
	// ListWhatsAppConversations returns a phone-grouped view over wa_messages:
	// one row per counterpart phone with its most recent message + unread count.
	// Powers the standalone WhatsApp inbox page on the CRM web app.
	ListWhatsAppConversations(context.Context, *ListWhatsAppConversationsRequest) (*ListWhatsAppConversationsResponse, error)
	ListWhatsAppTemplates(context.Context, *ListWhatsAppTemplatesRequest) (*ListWhatsAppTemplatesResponse, error)
	HandleWhatsAppWebhook(context.Context, *WhatsAppWebhookRequest) (*WhatsAppWebhookResponse, error)
	// Wazzup24 messaging RPCs — separate provider mirroring the WhatsApp channel
	// that's still connected to AmoCRM. Lets the new CRM surface the same chats
	// without disrupting AmoCRM's existing Wazzup integration.
	SendWazzupMessage(context.Context, *SendWazzupMessageRequest) (*SendWazzupMessageResponse, error)
