	UpdateTelephonyCallState(context.Context, *UpdateTelephonyCallStateRequest) (*UpdateTelephonyCallStateResponse, error)
	ListTelephonyCallsByOrg(context.Context, *ListTelephonyCallsByOrgRequest) (*ListTelephonyCallsByOrgResponse, error)
	ListOrphanedTelephonyCalls(context.Context, *ListOrphanedTelephonyCallsRequest) (*ListOrphanedTelephonyCallsResponse, error)
	LookupEntityByPhone(context.Context, *LookupEntityByPhoneRequest) (*LookupEntityByPhoneResponse, error)
	UpsertTelephonyPipelineDID(context.Context, *UpsertTelephonyPipelineDIDRequest) (*UpsertTelephonyPipelineDIDResponse, error)
	ListTelephonyPipelineDIDs(context.Context, *ListTelephonyPipelineDIDsRequest) (*ListTelephonyPipelineDIDsResponse, error)
	DeleteTelephonyPipelineDID(context.Context, *DeleteTelephonyPipelineDIDRequest) (*DeleteTelephonyPipelineDIDResponse, error)
	UpsertTelephonyUserExtension(context.Context, *UpsertTelephonyUserExtensionRequest) (*UpsertTelephonyUserExtensionResponse, error)
	GetTelephonyUserExtension(context.Context, *GetTelephonyUserExtensionRequest) (*GetTelephonyUserExtensionResponse, error)
	// Phase 11: Admin CRUD for user extensions
	ListTelephonyUserExtensions(context.Context, *ListTelephonyUserExtensionsRequest) (*ListTelephonyUserExtensionsResponse, error)
	DeleteTelephonyUserExtension(context.Context, *DeleteTelephonyUserExtensionRequest) (*DeleteTelephonyUserExtensionResponse, error)
	UpdateTelephonyUserExtensionDND(context.Context, *UpdateTelephonyUserExtensionDNDRequest) (*UpdateTelephonyUserExtensionDNDResponse, error)
	// Phase 20 D-06: resolve PJSIP extension → owning org+user for Stasis outbound dispatch.
	LookupExtensionByNumber(context.Context, *LookupExtensionByNumberRequest) (*LookupExtensionByNumberResponse, error)
	GetTelephonyProviderConfig(context.Context, *GetTelephonyProviderConfigRequest) (*GetTelephonyProviderConfigResponse, error)
	UpdateTelephonyProviderConfig(context.Context, *UpdateTelephonyProviderConfigRequest) (*UpdateTelephonyProviderConfigResponse, error)
	// Phase 14: IVR Config + Business Hours + Greeting + Dialplan
	ListTelephonyIVRConfig(context.Context, *ListTelephonyIVRConfigRequest) (*ListTelephonyIVRConfigResponse, error)
	SaveTelephonyIVRConfig(context.Context, *SaveTelephonyIVRConfigRequest) (*SaveTelephonyIVRConfigResponse, error)
	GetTelephonyBusinessHours(context.Context, *GetTelephonyBusinessHoursRequest) (*GetTelephonyBusinessHoursResponse, error)
	SaveTelephonyBusinessHours(context.Context, *SaveTelephonyBusinessHoursRequest) (*SaveTelephonyBusinessHoursResponse, error)
	GetTelephonyIVRGreeting(context.Context, *GetTelephonyIVRGreetingRequest) (*GetTelephonyIVRGreetingResponse, error)
	UpsertTelephonyIVRGreeting(context.Context, *UpsertTelephonyIVRGreetingRequest) (*UpsertTelephonyIVRGreetingResponse, error)
	GetTelephonyDialplanData(context.Context, *GetTelephonyDialplanDataRequest) (*GetTelephonyDialplanDataResponse, error)
